sp_widget.client_script:
api.controller = function() {
    var c = this;
    c.selectedEvent = '';
    c.loading = false;

    c.loadAttendees = function() {
        if (!c.selectedEvent) {
            c.data.attendees = [];
            c.data.selectedEventTitle = '';
            c.data.totalRegistered = 0;
            c.data.totalCheckedIn = 0;
            return;
        }
        if (c.loading) return;
        c.loading = true;
        c.data.errorMsg = '';

        c.server.get({
            action: 'get_attendees',
            event_id: c.selectedEvent
        }).then(function(r) {
            c.data = r.data;
            c.loading = false;
        }, function() {
            c.data.errorMsg = 'Network error. Please try again.';
            c.loading = false;
        });
    };
};

sp_widget.css:
.sp-attendees .panel-heading {
    padding: 12px 20px;
}
.sp-attendees .panel-title {
    font-size: 16px;
    font-weight: 600;
    color: $text-color;
    margin: 0;
}
.sp-attendees .panel-title .glyphicon {
    margin-right: 8px;
    color: $brand-primary;
}
.sp-attendee-stats {
    margin-bottom: 16px;
    padding: 12px 0;
    border-bottom: 1px solid $border-tertiary;
}
.sp-attendee-stats .label {
    font-size: 13px;
    padding: 4px 10px;
}
.sp-input:focus {
    border-color: $brand-primary;
    box-shadow: 0 0 0 2px rgba($brand-primary, 0.15);
}
.sp-empty-state {
    padding: 48px 24px;
}
.sp-empty-icon {
    font-size: 40px;
    display: block;
    margin-bottom: 12px;
    opacity: 0.35;
    color: $text-muted;
}
.sp-empty-state h4 {
    font-weight: 600;
    color: $text-color;
    margin-bottom: 8px;
}

sp_widget.script:
(function() {
    data.events = [];
    data.attendees = [];
    data.selectedEventTitle = '';
    data.message = '';
    data.errorMsg = '';
    data.isAdmin = false;
    data.totalRegistered = 0;
    data.totalCheckedIn = 0;

    try {
        var userId = gs.getUserID();

        // Find clubs where user is president or vice_president
        var clubIds = [];
        var memGr = new GlideRecord('x_2097092_linq_club_membership');
        memGr.addQuery('member', userId);
        memGr.addQuery('role', 'IN', 'president,vice_president');
        memGr.addQuery('status', 'active');
        memGr.setLimit(50);
        memGr.query();

        while (memGr.next()) {
            clubIds.push(memGr.getValue('club') + '');
        }

        if (clubIds.length === 0) {
            data.message = 'You are not an admin of any clubs.';
            return;
        }

        data.isAdmin = true;

        // Get events for managed clubs (for dropdown)
        var evGr = new GlideRecord('x_2097092_linq_event');
        evGr.addQuery('club', 'IN', clubIds.join(','));
        evGr.orderByDesc('event_date');
        evGr.setLimit(100);
        evGr.query();

        while (evGr.next()) {
            data.events.push({
                sys_id: evGr.getUniqueValue(),
                title: evGr.getValue('title') + '',
                event_date: evGr.getDisplayValue('event_date') + ''
            });
        }

        // Handle get_attendees action
        if (input && input.action === 'get_attendees' && input.event_id) {
            data.attendees = [];
            data.totalRegistered = 0;
            data.totalCheckedIn = 0;

            // Get event title
            var selEvent = new GlideRecord('x_2097092_linq_event');
            if (selEvent.get(input.event_id)) {
                data.selectedEventTitle = selEvent.getValue('title') + '';
            }

            // Get registrations for this event
            var regGr = new GlideRecord('x_2097092_linq_registration');
            regGr.addQuery('event', input.event_id);
            regGr.setLimit(500);
            regGr.query();

            while (regGr.next()) {
                var regId = regGr.getUniqueValue();
                var studentName = regGr.getDisplayValue('student') + '';
                var regStatus = regGr.getValue('status') + '';
                data.totalRegistered++;

                // Check for attendance record
                var checkinStatus = 'Not checked in';
                var scanTime = '';

                var attGr = new GlideRecord('x_2097092_linq_attendance');
                attGr.addQuery('registration', regId);
                attGr.setLimit(1);
                attGr.query();

                if (attGr.next()) {
                    checkinStatus = 'Checked in';
                    scanTime = attGr.getDisplayValue('scan_timestamp') + '';
                    data.totalCheckedIn++;
                }

                data.attendees.push({
                    sys_id: regId,
                    student_name: studentName,
                    registration_status: regStatus,
                    checkin_status: checkinStatus,
                    scan_time: scanTime
                });
            }
        }
    } catch (e) {
        gs.error('linq-admin-attendees error: ' + e.message);
        data.errorMsg = 'An error occurred loading attendee data.';
    }
})();
